namespace sv_e8e8119be70c46318f0f85a1d749d7e4.Services;

public enum NotificationSeverity
{
    Info,
    Warning,
    Critical
}

public class NotificationItem
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public NotificationSeverity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; }
}

/// <summary>
/// Scoped service — one instance per circuit (per user connection on Server).
/// Multiple users get independent instances automatically.
/// </summary>
public class NotificationService
{
    private readonly List<NotificationItem> _notifications = [];
    private int _nextId = 1;

    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> All => _notifications.AsReadOnly();
    public int UnreadCount => _notifications.Count(n => !n.IsRead);

    public void Add(string title, NotificationSeverity severity)
    {
        _notifications.Insert(0, new NotificationItem
        {
            Id = _nextId++,
            Title = title,
            Severity = severity,
            Timestamp = DateTime.Now
        });
        OnChange?.Invoke();
    }

    public void MarkAsRead(int id)
    {
        var item = _notifications.FirstOrDefault(n => n.Id == id);
        if (item is not null)
        {
            item.IsRead = true;
            OnChange?.Invoke();
        }
    }

    public void Dismiss(int id)
    {
        _notifications.RemoveAll(n => n.Id == id);
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        foreach (var n in _notifications)
            n.IsRead = true;
        OnChange?.Invoke();
    }

    public IReadOnlyList<NotificationItem> GetRecentUnread(int count) =>
        _notifications.Where(n => !n.IsRead).Take(count).ToList();
}

@rendermode InteractiveServer
@inject NotificationService Notifications
@implements IDisposable

