}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationService Notifications
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<button class="btn btn-outline-secondary mb-3" @onclick="Notifications.MarkAllRead"
        disabled="@(Notifications.UnreadCount == 0)">
    Mark All Read
</button>

@if (Notifications.All.Count == 0)
{
    <p class="text-muted">No notifications.</p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Severity</th>
                <th>Read</th>
                <th>Timestamp</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var n in Notifications.All)
            {
                <tr class="@(n.IsRead ? "" : "table-active")">
                    <td>@n.Id</td>
                    <td>@n.Title</td>
                    <td>
                        <span class="badge @SeverityClass(n.Severity)">@n.Severity</span>
                    </td>
                    <td>@(n.IsRead ? "Yes" : "No")</td>
                    <td>@n.Timestamp.ToString("g")</td>
                    <td>
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-primary me-1"
                                    @onclick="() => Notifications.MarkAsRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => Notifications.Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        Notifications.OnChange += HandleChange;
    }

    private void HandleChange() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
