@page "/dashboard"
@rendermode InteractiveServer
@inject NotificationService Notifications
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="card mb-4">
    <div class="card-header">Recent Unread Notifications</div>
    <div class="card-body">
        @{
            var recent = Notifications.GetRecentUnread(3);
        }
        @if (recent.Count == 0)
        {
            <p class="text-muted mb-0">No unread notifications.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var n in recent)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-center">
                        <span>
                            <strong>@n.Title</strong>
                            <small class="text-muted ms-2">@n.Timestamp.ToString("g")</small>
                        </span>
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => Notifications.Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

<p class="text-muted">
    <em>A simulated notification arrives every 15 seconds while you're on this page.</em>
</p>

@code {
    private Timer? _timer;
    private int _simCount;

    private static readonly string[] SimulatedTitles =
    [
        "Server CPU usage high",
        "New user registered",
        "Deployment completed",
        "Disk space warning",
        "Payment received",
        "Certificate expiring soon"
    ];

    private static readonly NotificationSeverity[] SimulatedSeverities =
    [
        NotificationSeverity.Critical,
        NotificationSeverity.Info,
        NotificationSeverity.Info,
        NotificationSeverity.Warning,
        NotificationSeverity.Info,
        NotificationSeverity.Warning
    ];

    protected override void OnInitialized()
    {
        Notifications.OnChange += HandleChange;

        // Background timer only active on this page
        _timer = new Timer(OnTimerElapsed, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    private void OnTimerElapsed(object? state)
    {
        var index = _simCount % SimulatedTitles.Length;
        _simCount++;
        // Add fires OnChange, which calls InvokeAsync(StateHasChanged) on all subscribers
        InvokeAsync(() => Notifications.Add(SimulatedTitles[index], SimulatedSeverities[index]));
    }

    private void HandleChange() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        _timer?.Dispose();
        Notifications.OnChange -= HandleChange;
    }
}

